import React, { useState, useMemo } from 'react';
import { Button, Input, Select, Modal, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';
import { ccdcService } from '../../../services/ccdc/ccdcService';
import { masterService } from '../../../services/master/masterService';
import type { ToolsEquipmentDto } from '../../../services/master/models';
import { formatDate, formatNumber, formatVnd } from '../../../utils/formatters';
import { normalizeCodeOptional } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import { CatalogCompanyTh, CatalogCompanyTd, CatalogCompanyField } from '../../../components/catalog';
import { useCompanyLabelMap } from '../../../hooks/useCompanyLabelMap';
import styles from '../../../styles/erpPage.module.css';
import { selectPlaceholderClass } from '../../../utils/selectField';

const TEST_ID = 'dm-ccdc-quan-ly';

type EntryFormErrors = Partial<Record<'toolsEquipmentId' | 'transactionDate' | 'quantity', string>>;
type IssueFormErrors = Partial<Record<'toolsEquipmentId' | 'transactionDate' | 'quantity', string>>;

type Row = Record<string, unknown>;

const EMPTY_ENTRY_FORM = { toolsEquipmentId: '', transactionDate: '', quantity: '', unitPrice: '', voucherNumber: '', note: '' };
const EMPTY_ISSUE_FORM = { toolsEquipmentId: '', transactionDate: '', quantity: '', unitPrice: '', deptCode: '', note: '' };

const cell = (row: Row, key: string) => {
  const v = row[key];
  if (v == null || v === '') return '—';
  return String(v);
};

const rowKey = (row: Row, idx: number) => String(row.id ?? row.code ?? idx);

const CcdcQuanLyPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const { sessionCompanyId } = useCompanyLabelMap();
  const [tab, setTab] = useState<'inventory' | 'entry' | 'issue'>('inventory');
  const [inventory, setInventory] = useState<Row[]>([]);
  const [entries, setEntries] = useState<Row[]>([]);
  const [issues, setIssues] = useState<Row[]>([]);
  const [ccdcList, setCcdcList] = useState<ToolsEquipmentDto[]>([]);
  const [loading, setLoading] = useState(false);
  const [entryModalOpen, setEntryModalOpen] = useState(false);
  const [issueModalOpen, setIssueModalOpen] = useState(false);
  const [entryForm, setEntryForm] = useState(EMPTY_ENTRY_FORM);
  const [issueForm, setIssueForm] = useState(EMPTY_ISSUE_FORM);
  const [entryErrors, setEntryErrors] = useState<EntryFormErrors>({});
  const [issueErrors, setIssueErrors] = useState<IssueFormErrors>({});
  const [saving, setSaving] = useState(false);
  const [reloadKey, setReloadKey] = useState(0);

  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      masterService.getToolsEquipment({ showInactive: false, page: 1, pageSize: 500 })
        .then(data => { if (!cancelled) setCcdcList(data.items); })
        .catch(() => { /* optional */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      const loadInventory = tab === 'inventory' ? ccdcService.getInventory() : Promise.resolve([] as Row[]);
      const loadEntry = tab === 'entry' ? ccdcService.getTransactions({ type: 'Entry' }) : Promise.resolve([] as Row[]);
      const loadIssue = tab === 'issue' ? ccdcService.getTransactions({ type: 'Issue' }) : Promise.resolve([] as Row[]);
      Promise.all([loadInventory, loadEntry, loadIssue])
        .then(([inv, ent, iss]) => {
          if (!cancelled) {
            if (tab === 'inventory') setInventory(inv);
            if (tab === 'entry') setEntries(ent);
            if (tab === 'issue') setIssues(iss);
          }
        })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải dữ liệu CCDC', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [tab, reloadKey, dispatch]);

  const ccdcOpts = useMemo(
    () => ccdcList.map(c => ({ value: c.id, label: `${c.code} — ${c.name}` })),
    [ccdcList],
  );

  const clearEntryFieldError = (key: keyof EntryFormErrors) => {
    setEntryErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const clearIssueFieldError = (key: keyof IssueFormErrors) => {
    setIssueErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validateEntry = (): EntryFormErrors => {
    const next: EntryFormErrors = {};
    if (!entryForm.toolsEquipmentId) next.toolsEquipmentId = 'Chọn CCDC';
    if (!entryForm.transactionDate?.trim()) next.transactionDate = 'Chọn ngày nhập';
    if (!entryForm.quantity?.trim() || Number(entryForm.quantity) <= 0) next.quantity = 'Nhập số lượng';
    return next;
  };

  const validateIssue = (): IssueFormErrors => {
    const next: IssueFormErrors = {};
    if (!issueForm.toolsEquipmentId) next.toolsEquipmentId = 'Chọn CCDC';
    if (!issueForm.transactionDate?.trim()) next.transactionDate = 'Chọn ngày cấp';
    if (!issueForm.quantity?.trim() || Number(issueForm.quantity) <= 0) next.quantity = 'Nhập số lượng';
    return next;
  };

  const openEntryModal = () => {
    setEntryForm(EMPTY_ENTRY_FORM);
    setEntryErrors({});
    setEntryModalOpen(true);
  };

  const openIssueModal = () => {
    setIssueForm(EMPTY_ISSUE_FORM);
    setIssueErrors({});
    setIssueModalOpen(true);
  };

  const handleCreateEntry = async () => {
    const nextErrors = validateEntry();
    if (Object.keys(nextErrors).length > 0) {
      setEntryErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      await ccdcService.createEntry({
        toolsEquipmentId: entryForm.toolsEquipmentId,
        transactionDate: entryForm.transactionDate,
        quantity: Number(entryForm.quantity),
        unitPrice: entryForm.unitPrice ? Number(entryForm.unitPrice) : undefined,
        voucherNumber: entryForm.voucherNumber || undefined,
        note: entryForm.note || undefined,
        type: 'Entry',
      });
      dispatch(addToast({ message: 'Ghi nhận nhập CCDC thành công', type: 'success' }));
      setEntryModalOpen(false);
      setEntryForm(EMPTY_ENTRY_FORM);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleCreateIssue = async () => {
    const nextErrors = validateIssue();
    if (Object.keys(nextErrors).length > 0) {
      setIssueErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      await ccdcService.createIssue({
        toolsEquipmentId: issueForm.toolsEquipmentId,
        transactionDate: issueForm.transactionDate,
        quantity: Number(issueForm.quantity),
        unitPrice: issueForm.unitPrice ? Number(issueForm.unitPrice) : undefined,
        deptCode: normalizeCodeOptional(issueForm.deptCode),
        note: issueForm.note || undefined,
        type: 'Issue',
      });
      dispatch(addToast({ message: 'Ghi nhận cấp phát CCDC thành công', type: 'success' }));
      setIssueModalOpen(false);
      setIssueForm(EMPTY_ISSUE_FORM);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const renderInventory = () => (
    <div className={styles.tableWrapper}>
      <table className={styles.table}>
        <thead>
          <tr>
            <th>Mã</th>
            <th>Tên</th>
                  <CatalogCompanyTh />
            <th>Đơn vị</th>
            <th>SL</th>
            <th className={styles.colRight}>Đơn giá</th>
            <th>Ngày cấp</th>
          </tr>
        </thead>
        <tbody>
          {inventory.map((r, idx) => (
            <tr key={rowKey(r, idx)}>
              <td><code>{cell(r, 'code')}</code></td>
              <td>{cell(r, 'name')}</td>
              <td>{cell(r, 'deptName')}</td>
              <td>{cell(r, 'quantity')}</td>
              <td className={styles.colRight}>{typeof r.unitPrice === 'number' ? formatVnd(r.unitPrice) : cell(r, 'unitPrice')}</td>
              <td>{typeof r.issueDate === 'string' ? formatDate(r.issueDate) : cell(r, 'issueDate')}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const renderTransactions = (rows: Row[]) => (
    <div className={styles.tableWrapper}>
      <table className={styles.table}>
        <thead>
          <tr>
            <th>Ngày</th>
            <th>Số CT</th>
            <th>Mã CCDC</th>
            <th>Tên</th>
            <th>SL</th>
            <th className={styles.colRight}>Đơn giá</th>
            <th>Ghi chú</th>
          </tr>
        </thead>
        <tbody>
          {rows.map((r, idx) => (
            <tr key={rowKey(r, idx)}>
              <td>{typeof r.transactionDate === 'string' ? formatDate(r.transactionDate) : cell(r, 'transactionDate')}</td>
              <td>{cell(r, 'voucherNumber')}</td>
              <td><code>{cell(r, 'ccdcCode') || cell(r, 'code')}</code></td>
              <td>{cell(r, 'ccdcName') || cell(r, 'name')}</td>
              <td>{cell(r, 'quantity')}</td>
              <td className={styles.colRight}>{typeof r.unitPrice === 'number' ? formatNumber(r.unitPrice as number) : cell(r, 'unitPrice')}</td>
              <td>{cell(r, 'note')}</td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );

  const currentRows = tab === 'inventory' ? inventory : tab === 'entry' ? entries : issues;

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-clipboard-list" /> Quản lý CCDC</h1>
        </div>
        <div className={styles.headerActions}>
          {tab === 'entry' && (
            <Button variant="primary" onClick={openEntryModal} data-testid={`${TEST_ID}-add-entry-btn`}>
              <i className="fas fa-plus" /> Nhập CCDC
            </Button>
          )}
          {tab === 'issue' && (
            <Button variant="primary" onClick={openIssueModal} data-testid={`${TEST_ID}-add-issue-btn`}>
              <i className="fas fa-plus" /> Cấp phát
            </Button>
          )}
        </div>
      </div>

      <div className={styles.tabs}>
        <button type="button" className={tab === 'inventory' ? styles.tabActive : styles.tab} onClick={() => setTab('inventory')}>
          Tồn kho
        </button>
        <button type="button" className={tab === 'entry' ? styles.tabActive : styles.tab} onClick={() => setTab('entry')}>
          Nhập CCDC
        </button>
        <button type="button" className={tab === 'issue' ? styles.tabActive : styles.tab} onClick={() => setTab('issue')}>
          Cấp phát
        </button>
      </div>

      {(tab === 'entry' || tab === 'issue') && (
        <div className={styles.filtersBar} data-testid={`${TEST_ID}-filters`}>
          <ListSearchRefreshButtons testIdPrefix={TEST_ID} onSearch={refresh} onRefresh={refresh} showSearch={false} />
        </div>
      )}

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : currentRows.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có dữ liệu</p></div>
        ) : tab === 'inventory' ? renderInventory() : renderTransactions(currentRows)}
      </div>

      <Modal isOpen={entryModalOpen} onClose={() => setEntryModalOpen(false)} title="Nhập CCDC">
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form-entry`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-toolsEquipmentId`}>
              <label className={styles.label}>CCDC *</label>
              <Select
                value={entryForm.toolsEquipmentId}
                error={entryErrors.toolsEquipmentId}
                placeholder="— Chọn CCDC —"
                required
                className={selectPlaceholderClass(entryForm.toolsEquipmentId)}
                onChange={e => {
                  clearEntryFieldError('toolsEquipmentId');
                  setEntryForm(f => ({ ...f, toolsEquipmentId: e.target.value }));
                }}
                options={ccdcOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-transactionDate`}>
              <label className={styles.label}>Ngày nhập *</label>
              <Input
                type="date"
                value={entryForm.transactionDate}
                error={entryErrors.transactionDate}
                onChange={e => {
                  clearEntryFieldError('transactionDate');
                  setEntryForm(f => ({ ...f, transactionDate: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-quantity`}>
              <label className={styles.label}>Số lượng *</label>
              <Input
                type="number"
                value={entryForm.quantity}
                error={entryErrors.quantity}
                onChange={e => {
                  clearEntryFieldError('quantity');
                  setEntryForm(f => ({ ...f, quantity: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-unitPrice`}>
              <label className={styles.label}>Đơn giá</label>
              <Input type="number" value={entryForm.unitPrice} onChange={e => setEntryForm(f => ({ ...f, unitPrice: e.target.value }))} />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-voucherNumber`}>
              <label className={styles.label}>Số chứng từ</label>
              <Input value={entryForm.voucherNumber} onChange={e => setEntryForm(f => ({ ...f, voucherNumber: e.target.value }))} />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-note`}>
              <label className={styles.label}>Ghi chú</label>
              <Input value={entryForm.note} onChange={e => setEntryForm(f => ({ ...f, note: e.target.value }))} />
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyId={sessionCompanyId}
          />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={() => setEntryModalOpen(false)}>Hủy</Button>
            <Button variant="primary" onClick={handleCreateEntry} disabled={saving} data-testid={`${TEST_ID}-save-entry-btn`}>
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>

      <Modal isOpen={issueModalOpen} onClose={() => setIssueModalOpen(false)} title="Cấp phát CCDC">
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form-issue`}>
          <div className={styles.formGrid}>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueToolsEquipmentId`}>
              <label className={styles.label}>CCDC *</label>
              <Select
                value={issueForm.toolsEquipmentId}
                error={issueErrors.toolsEquipmentId}
                placeholder="— Chọn CCDC —"
                required
                className={selectPlaceholderClass(issueForm.toolsEquipmentId)}
                onChange={e => {
                  clearIssueFieldError('toolsEquipmentId');
                  setIssueForm(f => ({ ...f, toolsEquipmentId: e.target.value }));
                }}
                options={ccdcOpts}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueTransactionDate`}>
              <label className={styles.label}>Ngày cấp *</label>
              <Input
                type="date"
                value={issueForm.transactionDate}
                error={issueErrors.transactionDate}
                onChange={e => {
                  clearIssueFieldError('transactionDate');
                  setIssueForm(f => ({ ...f, transactionDate: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueQuantity`}>
              <label className={styles.label}>Số lượng *</label>
              <Input
                type="number"
                value={issueForm.quantity}
                error={issueErrors.quantity}
                onChange={e => {
                  clearIssueFieldError('quantity');
                  setIssueForm(f => ({ ...f, quantity: e.target.value }));
                }}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueUnitPrice`}>
              <label className={styles.label}>Đơn giá</label>
              <Input type="number" value={issueForm.unitPrice} onChange={e => setIssueForm(f => ({ ...f, unitPrice: e.target.value }))} />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-deptCode`}>
              <label className={styles.label}>Mã đơn vị</label>
              <Input
                value={issueForm.deptCode}
                className={styles.codeInput}
                onChange={e => setIssueForm(f => ({ ...f, deptCode: normalizeCodeOptional(e.target.value) ?? '' }))}
              />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-issueNote`}>
              <label className={styles.label}>Ghi chú</label>
              <Input value={issueForm.note} onChange={e => setIssueForm(f => ({ ...f, note: e.target.value }))} />
            </div>
          </div>
          <CatalogCompanyField
            testIdPrefix={TEST_ID}
            companyId={sessionCompanyId}
          />
          <div className={styles.modalActions}>
            <Button variant="secondary" onClick={() => setIssueModalOpen(false)}>Hủy</Button>
            <Button variant="primary" onClick={handleCreateIssue} disabled={saving} data-testid={`${TEST_ID}-save-issue-btn`}>
              {saving ? 'Đang lưu...' : 'Lưu'}
            </Button>
          </div>
        </div>
      </Modal>
    </div>
  );
};

export default CcdcQuanLyPage;
